import React from "react";

const coreCompetencies = [
  "Product Development & Validation",
  "Process Improvement & Optimization",
  "Root Cause Analysis (RCA, 5 Why, Fishbone)",
  "Statistical Quality Control (Cp, Cpk)",
  "GD&T & Engineering Inspection",
  "Manufacturing Process Understanding",
  "Data Analysis & Technical Reporting",
];

const skillAreas = [
  {
    title: "Skills",
    items: [
      "Process Engineering",
      "Lean Manufacturing (basic)",
      "Problem Solving Tools (7QC tools)",
      "Continuous Improvement",
    ],
  },
  {
    title: "Tools",
    items: ["MATLAB Simulink", "Arduino IDE", "MS Excel", "PowerPoint", "Word"],
  },
];

function Skills() {
  return (
    <div className="section-shell">
      <div className="section-heading">
        <p className="eyebrow">Skills</p>
        <h2>Technical skills and core strengths</h2>
      </div>

      <div className="content-card skills-highlight">
        <h3>Technical Skills</h3>
        <div className="timeline-strip" aria-label="Technical skills timeline">
          <span className="timeline-chip">2022 - 2026</span>
          <span className="timeline-chip">2021</span>
          <span className="timeline-chip">2019</span>
        </div>
      </div>

      <div className="skills-grid skills-grid--expanded">
        <article className="skill-card skill-card--full">
          <h3>Core Competencies</h3>
          <ul>
            {coreCompetencies.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
        </article>

        {skillAreas.map((group) => (
          <article className="skill-card" key={group.title}>
            <h3>{group.title}</h3>
            <ul>
              {group.items.map((item) => (
                <li key={item}>{item}</li>
              ))}
            </ul>
          </article>
        ))}
      </div>
    </div>
  );
}

export default Skills;
